import { Module } from '@nestjs/common';
import { TypeOrmModule } from '@nestjs/typeorm';
import { CatalogController } from './catalog.controller';
import { CatalogService } from './catalog.service';
import { Source } from './entities/source.entity';
import { TradingPair } from './entities/trading-pair.entity';

@Module({
  imports: [TypeOrmModule.forFeature([Source, TradingPair])],
  controllers: [CatalogController],
  providers: [CatalogService],
})
export class CatalogModule {}

import { Module } from '@nestjs/common';
import { TypeOrmModule } from '@nestjs/typeorm';
import { HttpModule } from '@nestjs/axios';
import { CatalogController } from './catalog.controller';
import { CatalogService } from './catalog.service';
import { Source } from './entities/source.entity';
import { TradingPair } from './entities/trading-pair.entity';

@Module({
  imports: [
    TypeOrmModule.forFeature([Source, TradingPair]),
    HttpModule.register({ timeout: 10000 }),
  ],
  controllers: [CatalogController],
  providers: [CatalogService],
})
export class CatalogModule {}

import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { Source } from './entities/source.entity';
import { TradingPair } from './entities/trading-pair.entity';

@Injectable()
export class CatalogService {
  constructor(
    @InjectRepository(Source)
    private readonly sourcesRepo: Repository<Source>,
    @InjectRepository(TradingPair)
    private readonly pairsRepo: Repository<TradingPair>,
  ) {}

  getSources(): Promise<Source[]> {
    return this.sourcesRepo.find({ where: { isActive: true } });
  }

  getPairs(): Promise<TradingPair[]> {
    return this.pairsRepo.find();
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { ConfigService } from '@nestjs/config';
import { HttpService } from '@nestjs/axios';
import { firstValueFrom } from 'rxjs';
import { Source } from './entities/source.entity';
import { TradingPair } from './entities/trading-pair.entity';
import {
  parseMarketDataKey,
  makePairId,
  makePairDisplayName,
  tokenDisplayName,
  SOURCE_META,
} from '../prices/market-data-keys';

/** DTO источника для фронтенда */
export interface SourceDto {
  id: string;
  name: string;
  displayName: string;
  type: 'dex' | 'cex';
  icon: string | null;
  isActive: boolean;
}

/** DTO торговой пары для фронтенда */
export interface PairDto {
  id: string;
  base: string;
  quote: string;
  displayName: string;
}

@Injectable()
export class CatalogService {
  private readonly logger = new Logger(CatalogService.name);
  private readonly marketDataUrl: string;

  constructor(
    @InjectRepository(Source)
    private readonly sourcesRepo: Repository<Source>,
    @InjectRepository(TradingPair)
    private readonly pairsRepo: Repository<TradingPair>,
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
  ) {
    this.marketDataUrl =
      this.configService.get<string>('marketData.url') ?? 'http://45.135.182.251:3002';
  }

  /**
   * Получить список источников из ключей arbiDexMarketData.
   * Если сервис недоступен — fallback на БД.
   */
  async getSources(): Promise<SourceDto[]> {
    try {
      const keys = await this.fetchMarketDataKeys();
      return this.deriveSources(keys);
    } catch (err) {
      this.logger.warn(`Fallback на БД для sources: ${err.message}`);
      const dbSources = await this.sourcesRepo.find({ where: { isActive: true } });
      return dbSources.map((s) => ({
        ...s,
        type: s.type as 'dex' | 'cex',
        icon: s.icon ?? null,
      }));
    }
  }

  /**
   * Получить список торговых пар из ключей arbiDexMarketData.
   * Если сервис недоступен — fallback на БД.
   */
  async getPairs(): Promise<PairDto[]> {
    try {
      const keys = await this.fetchMarketDataKeys();
      return this.derivePairs(keys);
    } catch (err) {
      this.logger.warn(`Fallback на БД для pairs: ${err.message}`);
      return this.pairsRepo.find();
    }
  }

  /** Запрос GET /store/keys из arbiDexMarketData */
  private async fetchMarketDataKeys(): Promise<string[]> {
    const response = await firstValueFrom(
      this.httpService.get<string[]>(`${this.marketDataUrl}/store/keys`),
    );
    return response.data;
  }

  /** Извлечь уникальные источники из ключей */
  private deriveSources(keys: string[]): SourceDto[] {
    const seen = new Map<string, SourceDto>();

    for (const key of keys) {
      const parsed = parseMarketDataKey(key);
      if (!parsed) continue;

      if (!seen.has(parsed.source)) {
        const meta = SOURCE_META[parsed.source];
        seen.set(parsed.source, {
          id: parsed.source,
          name: parsed.source,
          displayName: meta?.displayName ?? parsed.source,
          type: meta?.type ?? (parsed.source.startsWith('dex:') ? 'dex' : 'cex'),
          icon: null,
          isActive: true,
        });
      }
    }

    return Array.from(seen.values()).sort((a, b) =>
      a.type.localeCompare(b.type) || a.displayName.localeCompare(b.displayName),
    );
  }

  /** Извлечь уникальные торговые пары из ключей */
  private derivePairs(keys: string[]): PairDto[] {
    const seen = new Map<string, PairDto>();

    for (const key of keys) {
      const parsed = parseMarketDataKey(key);
      if (!parsed) continue;

      const pairId = makePairId(parsed.base, parsed.quote);
      if (!seen.has(pairId)) {
        seen.set(pairId, {
          id: pairId,
          base: tokenDisplayName(parsed.base),
          quote: tokenDisplayName(parsed.quote),
          displayName: makePairDisplayName(parsed.base, parsed.quote),
        });
      }
    }

    return Array.from(seen.values()).sort((a, b) =>
      a.displayName.localeCompare(b.displayName),
    );
  }
}

import {
  WebSocketGateway,
  WebSocketServer,
  OnGatewayConnection,
  OnGatewayDisconnect,
} from '@nestjs/websockets';
import { Logger } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import type { Namespace, Socket } from 'socket.io';
import { io as ioClient, Socket as ClientSocket } from 'socket.io-client';
import { Subscription } from '../subscriptions/entities/subscription.entity';
import { getPriceStoreKeys } from '../prices/price-key-mapping';

/** Сообщение dataChange от arbiDexMarketData */
interface DataChangeMessage {
  key: string;
  point: { t: number; v: number };
}

/** Состояние одной комнаты — подключение к arbiDexMarketData */
interface RoomState {
  /** Socket.IO клиент к arbiDexMarketData /store namespace */
  upstreamSocket: ClientSocket;
  /** Ключи, на которые подписана комната */
  bidKey: string;
  askKey: string;
}

/**
 * Socket.IO Gateway для live-chart.
 *
 * Клиент подключается к namespace /live-chart, передавая:
 *   - handshake.auth.token  — JWT access-токен
 *   - handshake.query.subscriptionId — UUID подписки
 *
 * Сервер помещает клиента в room "subscription:<id>" и
 * подключается к arbiDexMarketData /store для получения
 * реальных ценовых обновлений, которые ретранслирует клиентам.
 */
@WebSocketGateway({
  namespace: '/live-chart',
  cors: {
    origin: '*',
    credentials: false,
  },
})
export class LiveChartGateway
  implements OnGatewayConnection, OnGatewayDisconnect
{
  @WebSocketServer()
  server: Namespace;

  private readonly logger = new Logger(LiveChartGateway.name);

  /** URL сервиса arbiDexMarketData */
  private readonly marketDataUrl: string;

  /** roomId → состояние подключения к upstream */
  private readonly rooms = new Map<string, RoomState>();

  /** socketId → roomId */
  private readonly socketRooms = new Map<string, string>();

  constructor(
    private readonly jwtService: JwtService,
    private readonly configService: ConfigService,
    @InjectRepository(Subscription)
    private readonly subsRepo: Repository<Subscription>,
  ) {
    this.marketDataUrl =
      this.configService.get<string>('marketData.url') ?? 'http://45.135.182.251:3002';
  }

  /** Вызывается при подключении клиента */
  async handleConnection(client: Socket): Promise<void> {
    // 1. Верификация JWT
    const token = client.handshake.auth?.token as string | undefined;
    if (token) {
      try {
        this.jwtService.verify(token, {
          secret: this.configService.get<string>('jwt.accessSecret'),
        });
      } catch {
        this.logger.warn(`Клиент ${client.id}: неверный JWT, отключаем`);
        client.disconnect();
        return;
      }
    }

    // 2. Получаем subscriptionId из query-параметров
    const subscriptionId = client.handshake.query?.subscriptionId as
      | string
      | undefined;
    if (!subscriptionId) {
      this.logger.warn(
        `Клиент ${client.id}: subscriptionId не передан, отключаем`,
      );
      client.disconnect();
      return;
    }

    const roomId = `subscription:${subscriptionId}`;

    // 3. Добавляем клиента в room
    void client.join(roomId);
    this.socketRooms.set(client.id, roomId);
    this.logger.log(`Клиент ${client.id} вошёл в комнату ${roomId}`);

    // 4. Если upstream-подключение для room ещё не создано — создаём
    if (!this.rooms.has(roomId)) {
      await this.startRoom(roomId, subscriptionId);
    }
  }

  /** Вызывается при отключении клиента */
  handleDisconnect(client: Socket): void {
    const roomId = this.socketRooms.get(client.id);
    if (!roomId) return;

    this.socketRooms.delete(client.id);
    this.logger.log(`Клиент ${client.id} покинул комнату ${roomId}`);

    // Проверяем, остались ли ещё клиенты в комнате
    const room = this.server.adapter.rooms?.get(roomId);
    if (!room || room.size === 0) {
      this.stopRoom(roomId);
    }
  }

  /**
   * Подключается к arbiDexMarketData Socket.IO /store namespace
   * и подписывается на ключи bid/ask для данной подписки.
   */
  private async startRoom(
    roomId: string,
    subscriptionId: string,
  ): Promise<void> {
    // Получаем подписку из БД для определения реальных ключей
    const sub = await this.subsRepo.findOne({
      where: { id: subscriptionId },
    });

    let bidKey = 'dex:arbitrum|WETH/USDC|bidPrice';
    let askKey = 'dex:arbitrum|WETH/USDC|askPrice';

    if (sub) {
      const keys = getPriceStoreKeys(sub.sourceId, sub.pairId);
      if (keys) {
        bidKey = keys.bidKey;
        askKey = keys.askKey;
        this.logger.log(
          `Комната ${roomId}: маппинг найден → bid=${bidKey}, ask=${askKey}`,
        );
      } else {
        this.logger.warn(
          `Комната ${roomId}: маппинг не найден для sourceId="${sub.sourceId}", pairId="${sub.pairId}", используем fallback`,
        );
      }
    } else {
      this.logger.warn(
        `Комната ${roomId}: подписка не найдена, используем fallback-ключи`,
      );
    }

    // Подключаемся к arbiDexMarketData Socket.IO /store namespace
    const upstreamSocket = ioClient(`${this.marketDataUrl}/store`, {
      transports: ['websocket'],
      reconnection: true,
      reconnectionAttempts: 10,
      reconnectionDelay: 2000,
    });

    upstreamSocket.on('connect', () => {
      this.logger.log(
        `Комната ${roomId}: подключено к arbiDexMarketData /store (${upstreamSocket.id})`,
      );

      // Подписываемся на нужные ключи
      upstreamSocket.emit('subscribe', { keys: [bidKey, askKey] });
    });

    upstreamSocket.on('subscribed', (info: { keys: string[] | 'all' }) => {
      this.logger.log(
        `Комната ${roomId}: подписка на ключи подтверждена: ${JSON.stringify(info.keys)}`,
      );
    });

    // Ретрансляция dataChange → priceUpdate
    upstreamSocket.on('dataChange', (msg: DataChangeMessage) => {
      this.server.to(roomId).emit('priceUpdate', {
        key: msg.key,
        point: msg.point,
      });
    });

    upstreamSocket.on('connect_error', (err: Error) => {
      this.logger.error(
        `Комната ${roomId}: ошибка подключения к arbiDexMarketData — ${err.message}`,
      );
    });

    upstreamSocket.on('disconnect', (reason: string) => {
      this.logger.warn(
        `Комната ${roomId}: upstream отключён — ${reason}`,
      );
    });

    const state: RoomState = {
      upstreamSocket,
      bidKey,
      askKey,
    };

    this.rooms.set(roomId, state);
    this.logger.log(`Запущен upstream для комнаты ${roomId}`);
  }

  /** Останавливает upstream-подключение для комнаты */
  private stopRoom(roomId: string): void {
    const state = this.rooms.get(roomId);
    if (state) {
      // Отписываемся и отключаемся от arbiDexMarketData
      state.upstreamSocket.emit('unsubscribe');
      state.upstreamSocket.disconnect();
      this.rooms.delete(roomId);
      this.logger.log(
        `Upstream для комнаты ${roomId} остановлен (нет клиентов)`,
      );
    }
  }
}

import {
  WebSocketGateway,
  WebSocketServer,
  OnGatewayConnection,
  OnGatewayDisconnect,
} from '@nestjs/websockets';
import { Logger } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import type { Namespace, Socket } from 'socket.io';
import { io as ioClient, Socket as ClientSocket } from 'socket.io-client';
import { Subscription } from '../subscriptions/entities/subscription.entity';
import { buildStoreKeys, detectKeyFormat } from '../prices/market-data-keys';

/** Сообщение dataChange от arbiDexMarketData */
interface DataChangeMessage {
  key: string;
  point: { t: number; v: number };
}

/** Состояние одной комнаты — подключение к arbiDexMarketData */
interface RoomState {
  /** Socket.IO клиент к arbiDexMarketData /store namespace */
  upstreamSocket: ClientSocket;
  /** Ключи, на которые подписана комната */
  bidKey: string;
  askKey: string;
}

/**
 * Socket.IO Gateway для live-chart.
 *
 * Клиент подключается к namespace /live-chart, передавая:
 *   - handshake.auth.token  — JWT access-токен
 *   - handshake.query.subscriptionId — UUID подписки
 *
 * Сервер помещает клиента в room "subscription:<id>" и
 * подключается к arbiDexMarketData /store для получения
 * реальных ценовых обновлений, которые ретранслирует клиентам.
 */
@WebSocketGateway({
  namespace: '/live-chart',
  cors: {
    origin: '*',
    credentials: false,
  },
})
export class LiveChartGateway
  implements OnGatewayConnection, OnGatewayDisconnect
{
  @WebSocketServer()
  server: Namespace;

  private readonly logger = new Logger(LiveChartGateway.name);

  /** URL сервиса arbiDexMarketData */
  private readonly marketDataUrl: string;

  /** roomId → состояние подключения к upstream */
  private readonly rooms = new Map<string, RoomState>();

  /** socketId → roomId */
  private readonly socketRooms = new Map<string, string>();

  constructor(
    private readonly jwtService: JwtService,
    private readonly configService: ConfigService,
    @InjectRepository(Subscription)
    private readonly subsRepo: Repository<Subscription>,
  ) {
    this.marketDataUrl =
      this.configService.get<string>('marketData.url') ?? 'http://45.135.182.251:3002';
  }

  /** Вызывается при подключении клиента */
  async handleConnection(client: Socket): Promise<void> {
    // 1. Верификация JWT
    const token = client.handshake.auth?.token as string | undefined;
    if (token) {
      try {
        this.jwtService.verify(token, {
          secret: this.configService.get<string>('jwt.accessSecret'),
        });
      } catch {
        this.logger.warn(`Клиент ${client.id}: неверный JWT, отключаем`);
        client.disconnect();
        return;
      }
    }

    // 2. Получаем subscriptionId из query-параметров
    const subscriptionId = client.handshake.query?.subscriptionId as
      | string
      | undefined;
    if (!subscriptionId) {
      this.logger.warn(
        `Клиент ${client.id}: subscriptionId не передан, отключаем`,
      );
      client.disconnect();
      return;
    }

    const roomId = `subscription:${subscriptionId}`;

    // 3. Добавляем клиента в room
    void client.join(roomId);
    this.socketRooms.set(client.id, roomId);
    this.logger.log(`Клиент ${client.id} вошёл в комнату ${roomId}`);

    // 4. Если upstream-подключение для room ещё не создано — создаём
    if (!this.rooms.has(roomId)) {
      await this.startRoom(roomId, subscriptionId);
    }
  }

  /** Вызывается при отключении клиента */
  handleDisconnect(client: Socket): void {
    const roomId = this.socketRooms.get(client.id);
    if (!roomId) return;

    this.socketRooms.delete(client.id);
    this.logger.log(`Клиент ${client.id} покинул комнату ${roomId}`);

    // Проверяем, остались ли ещё клиенты в комнате
    const room = this.server.adapter.rooms?.get(roomId);
    if (!room || room.size === 0) {
      this.stopRoom(roomId);
    }
  }

  /**
   * Подключается к arbiDexMarketData Socket.IO /store namespace
   * и подписывается на ключи bid/ask для данной подписки.
   */
  private async startRoom(
    roomId: string,
    subscriptionId: string,
  ): Promise<void> {
    // Получаем подписку из БД для определения реальных ключей
    const sub = await this.subsRepo.findOne({
      where: { id: subscriptionId },
    });

    let bidKey = 'dex:arbitrumWETHUSdCbidPrice';
    let askKey = 'dex:arbitrumWETHUSDCaskPrice';

    if (sub) {
      // Определяем формат ключей на сервере
      let format: 'pipe' | 'concat' = 'concat';
      try {
        const resp = await fetch(`${this.marketDataUrl}/store/keys`);
        const allKeys: string[] = await resp.json();
        format = detectKeyFormat(allKeys);
      } catch { /* fallback */ }

      const keys = buildStoreKeys(sub.sourceId, sub.pairId, format);
      if (keys) {
        bidKey = keys.bidKey;
        askKey = keys.askKey;
        this.logger.log(
          `Комната ${roomId}: ключи построены → bid=${bidKey}, ask=${askKey}`,
        );
      } else {
        this.logger.warn(
          `Комната ${roomId}: не удалось построить ключи для sourceId="${sub.sourceId}", pairId="${sub.pairId}", используем fallback`,
        );
      }
    } else {
      this.logger.warn(
        `Комната ${roomId}: подписка не найдена, используем fallback-ключи`,
      );
    }

    // Подключаемся к arbiDexMarketData Socket.IO /store namespace
    const upstreamSocket = ioClient(`${this.marketDataUrl}/store`, {
      transports: ['websocket'],
      reconnection: true,
      reconnectionAttempts: 10,
      reconnectionDelay: 2000,
    });

    upstreamSocket.on('connect', () => {
      this.logger.log(
        `Комната ${roomId}: подключено к arbiDexMarketData /store (${upstreamSocket.id})`,
      );

      // Подписываемся на нужные ключи
      upstreamSocket.emit('subscribe', { keys: [bidKey, askKey] });
    });

    upstreamSocket.on('subscribed', (info: { keys: string[] | 'all' }) => {
      this.logger.log(
        `Комната ${roomId}: подписка на ключи подтверждена: ${JSON.stringify(info.keys)}`,
      );
    });

    // Ретрансляция dataChange → priceUpdate
    upstreamSocket.on('dataChange', (msg: DataChangeMessage) => {
      this.server.to(roomId).emit('priceUpdate', {
        key: msg.key,
        point: msg.point,
      });
    });

    upstreamSocket.on('connect_error', (err: Error) => {
      this.logger.error(
        `Комната ${roomId}: ошибка подключения к arbiDexMarketData — ${err.message}`,
      );
    });

    upstreamSocket.on('disconnect', (reason: string) => {
      this.logger.warn(
        `Комната ${roomId}: upstream отключён — ${reason}`,
      );
    });

    const state: RoomState = {
      upstreamSocket,
      bidKey,
      askKey,
    };

    this.rooms.set(roomId, state);
    this.logger.log(`Запущен upstream для комнаты ${roomId}`);
  }

  /** Останавливает upstream-подключение для комнаты */
  private stopRoom(roomId: string): void {
    const state = this.rooms.get(roomId);
    if (state) {
      // Отписываемся и отключаемся от arbiDexMarketData
      state.upstreamSocket.emit('unsubscribe');
      state.upstreamSocket.disconnect();
      this.rooms.delete(roomId);
      this.logger.log(
        `Upstream для комнаты ${roomId} остановлен (нет клиентов)`,
      );
    }
  }
}

/**
 * Утилиты для разбора ключей arbiDexMarketData.
 *
 * Поддерживает два формата ключей:
 * 1. С разделителем `|`:  `source|base|quote|field`  (напр. `mexc|ETH|USDT|bidPrice`)
 * 2. Без разделителей:    `sourceSymbolField`         (напр. `mexcETHUSDTbidPrice`)
 */

/** Результат разбора ключа */
export interface ParsedMarketKey {
  /** Источник: 'mexc', 'binance', 'dex:arbitrum', ... */
  source: string;
  /** Базовая валюта/токен: 'ETH', '0x82af...' */
  base: string;
  /** Котируемая валюта/токен: 'USDT', '0xaf88...' */
  quote: string;
  /** Поле: 'bidPrice' | 'askPrice' */
  field: 'bidPrice' | 'askPrice';
}

/** Маппинг адреса контракта → человекочитаемый символ */
const TOKEN_NAMES: Record<string, string> = {
  '0x82af49447d8a07e3bd95bd0d56f35241523fbab1': 'WETH',
  '0xaf88d065e77c8cc2239327c5edb3a432268e5831': 'USDC',
  '0xff970a61a04b1ca14834a43f5de4533ebddb5cc8': 'USDC.e',
  '0xfd086bc7cd5c481dcc9c85ebe478a1c0b69fcbb9': 'USDT',
  '0x2f2a2543b76a4166549f7aab2e75bef0aefc5b0f': 'WBTC',
  '0x912ce59144191c1204e64559fe8253a0e49e6548': 'ARB',
};

/** Маппинг источника → метаданные для каталога */
export const SOURCE_META: Record<string, { displayName: string; type: 'dex' | 'cex' }> = {
  'dex:arbitrum': { displayName: 'Arbitrum DEX', type: 'dex' },
  'binance':      { displayName: 'Binance',      type: 'cex' },
  'mexc':         { displayName: 'MEXC',          type: 'cex' },
  'bybit':        { displayName: 'Bybit',         type: 'cex' },
  'okx':          { displayName: 'OKX',           type: 'cex' },
  'kucoin':       { displayName: 'KuCoin',        type: 'cex' },
  'gateio':       { displayName: 'Gate.io',       type: 'cex' },
};

/** Известные префиксы источников, отсортированные по длине (longest first) */
const KNOWN_SOURCES_SORTED = Object.keys(SOURCE_META).sort((a, b) => b.length - a.length);

/** Известные символы CEX (для формата без разделителей) */
const KNOWN_SYMBOLS = ['ETHUSDT', 'ETHUSDC', 'BTCUSDT', 'BTCUSDC'];

/** Маппинг символа CEX → { base, quote } (для формата без разделителей) */
const SYMBOL_SPLIT: Record<string, { base: string; quote: string }> = {
  'ETHUSDT': { base: 'ETH', quote: 'USDT' },
  'ETHUSDC': { base: 'ETH', quote: 'USDC' },
  'BTCUSDT': { base: 'BTC', quote: 'USDT' },
  'BTCUSDC': { base: 'BTC', quote: 'USDC' },
};

/**
 * Разбирает ключ arbiDexMarketData в любом формате.
 * Возвращает null если ключ не удалось разобрать.
 */
export function parseMarketDataKey(key: string): ParsedMarketKey | null {
  // ── Формат с разделителем `|` ──
  if (key.includes('|')) {
    const parts = key.split('|');
    // source|base|quote|field — 4 части
    if (parts.length === 4) {
      const field = parts[3];
      if (field !== 'bidPrice' && field !== 'askPrice') return null;
      return { source: parts[0], base: parts[1], quote: parts[2], field };
    }
    return null;
  }

  // ── Формат без разделителей ──
  let field: 'bidPrice' | 'askPrice';
  let rest: string;

  if (key.endsWith('bidPrice')) {
    field = 'bidPrice';
    rest = key.slice(0, -8); // 'bidPrice'.length = 8
  } else if (key.endsWith('askPrice')) {
    field = 'askPrice';
    rest = key.slice(0, -8);
  } else {
    return null;
  }

  for (const src of KNOWN_SOURCES_SORTED) {
    if (rest.startsWith(src)) {
      const symbolPart = rest.slice(src.length);

      // Для DEX — ищем адреса контрактов (0x... + 0x...)
      if (src.startsWith('dex:')) {
        const addrMatch = symbolPart.match(/^(0x[0-9a-f]{40})(0x[0-9a-f]{40})$/i);
        if (addrMatch) {
          return { source: src, base: addrMatch[1].toLowerCase(), quote: addrMatch[2].toLowerCase(), field };
        }
        return null;
      }

      // Для CEX — ищем известный символ
      const split = SYMBOL_SPLIT[symbolPart];
      if (split) {
        return { source: src, base: split.base, quote: split.quote, field };
      }
      return null;
    }
  }

  return null;
}

/**
 * Преобразует адрес токена в человекочитаемое имя.
 * Если адрес неизвестен — возвращает укороченный адрес.
 */
export function tokenDisplayName(token: string): string {
  return TOKEN_NAMES[token.toLowerCase()] ?? `${token.slice(0, 6)}…${token.slice(-4)}`;
}

/**
 * Генерирует pairId из base и quote.
 * Для адресов использует человекочитаемые имена.
 */
export function makePairId(base: string, quote: string): string {
  const b = TOKEN_NAMES[base.toLowerCase()] ?? base;
  const q = TOKEN_NAMES[quote.toLowerCase()] ?? quote;
  return `${b}_${q}`;
}

/**
 * Генерирует displayName пары из base и quote.
 */
export function makePairDisplayName(base: string, quote: string): string {
  const b = TOKEN_NAMES[base.toLowerCase()] ?? base;
  const q = TOKEN_NAMES[quote.toLowerCase()] ?? quote;
  return `${b}/${q}`;
}

/**
 * Определяет формат ключей на сервере по массиву ключей.
 */
export function detectKeyFormat(keys: string[]): 'pipe' | 'concat' {
  return keys.some((k) => k.includes('|')) ? 'pipe' : 'concat';
}

/**
 * Генерирует ключи arbiDexMarketData (bid + ask) для данного sourceId + pairId.
 * Пробует оба формата и возвращает оба варианта для совместимости.
 */
export function buildStoreKeys(
  sourceId: string,
  pairId: string,
  format: 'pipe' | 'concat' = 'concat',
): { bidKey: string; askKey: string } | null {
  // pairId = 'ETH_USDT' или 'WETH_USDC'
  const parts = pairId.split('_');
  if (parts.length !== 2) return null;

  const [baseDisplay, quoteDisplay] = parts;

  // Обратный маппинг: символ → адрес (для DEX)
  const reverseTokens: Record<string, string> = {};
  for (const [addr, name] of Object.entries(TOKEN_NAMES)) {
    reverseTokens[name] = addr;
  }

  const base = reverseTokens[baseDisplay] ?? baseDisplay;
  const quote = reverseTokens[quoteDisplay] ?? quoteDisplay;

  if (format === 'pipe') {
    return {
      bidKey: `${sourceId}|${base}|${quote}|bidPrice`,
      askKey: `${sourceId}|${base}|${quote}|askPrice`,
    };
  }

  // Concat format
  if (sourceId.startsWith('dex:')) {
    // DEX: source + addr0 + addr1 + field
    return {
      bidKey: `${sourceId}${base}${quote}bidPrice`,
      askKey: `${sourceId}${base}${quote}askPrice`,
    };
  }

  // CEX: source + BASEQUOTE + field
  const symbol = `${base}${quote}`;
  return {
    bidKey: `${sourceId}${symbol}bidPrice`,
    askKey: `${sourceId}${symbol}askPrice`,
  };
}

/**
 * Маппинг sourceId + pairId → префикс источника и символ в PriceStore.
 *
 * Ключ PriceStore: `<sourcePrefix>|<symbol>|bidPrice` / `<sourcePrefix>|<symbol>|askPrice`
 *
 * Каждый CEX/DEX использует свой формат символа:
 * - binance: ETHUSDC (BASEQUOTE)
 * - mexc:    ETHUSDT (BASEQUOTE)
 * - bybit:   ETHUSDT (BASEQUOTE)
 * - okx:     ETH-USDT (BASE-QUOTE)
 * - kucoin:  ETH-USDT (BASE-QUOTE)
 * - gateio:  ETH_USDT (BASE_QUOTE)
 * - dex:arbitrum: WETH/USDC (BASE/QUOTE)
 */

export interface PriceKeyMapping {
  /** Префикс источника в PriceStore (например, 'binance', 'dex:arbitrum') */
  sourcePrefix: string;
  /** Символ пары в PriceStore (например, 'ETHUSDC', 'WETH/USDC') */
  symbol: string;
}

/**
 * Таблица маппинга: `sourceId::pairId` → PriceKeyMapping
 */
const MAPPING: Record<string, PriceKeyMapping> = {
  // ── Binance ──
  'cex_binance::USDC_WETH':  { sourcePrefix: 'binance', symbol: 'ETHUSDC' },
  'cex_binance::ETH_USDT':   { sourcePrefix: 'binance', symbol: 'ETHUSDT' },

  // ── MEXC ──
  'cex_mex::ETH_USDT':       { sourcePrefix: 'mexc', symbol: 'ETHUSDT' },
  'cex_mex::USDC_WETH':      { sourcePrefix: 'mexc', symbol: 'ETHUSDC' },

  // ── Bybit ──
  'cex_bybit::ETH_USDT':     { sourcePrefix: 'bybit', symbol: 'ETHUSDT' },
  'cex_bybit::USDC_WETH':    { sourcePrefix: 'bybit', symbol: 'ETHUSDC' },

  // ── OKX ──
  'cex_okx::ETH_USDT':       { sourcePrefix: 'okx', symbol: 'ETH-USDT' },
  'cex_okx::USDC_WETH':      { sourcePrefix: 'okx', symbol: 'ETH-USDC' },

  // ── KuCoin ──
  'cex_kucoin::ETH_USDT':    { sourcePrefix: 'kucoin', symbol: 'ETH-USDT' },
  'cex_kucoin::USDC_WETH':   { sourcePrefix: 'kucoin', symbol: 'ETH-USDC' },

  // ── Gate.io ──
  'cex_gateio::ETH_USDT':    { sourcePrefix: 'gateio', symbol: 'ETH_USDT' },
  'cex_gateio::USDC_WETH':   { sourcePrefix: 'gateio', symbol: 'ETH_USDC' },

  // ── DEX Arbitrum ──
  'dex_arbitrum::USDC_WETH':  { sourcePrefix: 'dex:arbitrum', symbol: 'WETH/USDC' },
};

/**
 * Получить PriceStore-ключи (bid + ask) для пары sourceId + pairId.
 * Возвращает null если маппинг не найден.
 */
export function getPriceStoreKeys(
  sourceId: string,
  pairId: string,
): { bidKey: string; askKey: string; mapping: PriceKeyMapping } | null {
  const m = MAPPING[`${sourceId}::${pairId}`];
  if (!m) return null;
  return {
    bidKey: `${m.sourcePrefix}|${m.symbol}|bidPrice`,
    askKey: `${m.sourcePrefix}|${m.symbol}|askPrice`,
    mapping: m,
  };
}

/**
 * Маппинг sourceId + pairId → префикс источника и символ в arbiDexMarketData.
 *
 * Ключ в arbiDexMarketData: `<sourcePrefix><symbol>bidPrice` / `<sourcePrefix><symbol>askPrice`
 * (без разделителей — ключи конкатенированы напрямую).
 *
 * Каждый CEX/DEX использует свой формат символа:
 * - binance: ETHUSDC (BASEQUOTE)
 * - mexc:    ETHUSDT (BASEQUOTE)
 * - bybit:   ETHUSDT (BASEQUOTE)
 * - okx:     ETHUSDT (BASEQUOTE)
 * - kucoin:  ETHUSDT (BASEQUOTE)
 * - gateio:  ETHUSDT (BASEQUOTE)
 * - dex:arbitrum: <tokenAddress0><tokenAddress1> (контракты токенов)
 */

export interface PriceKeyMapping {
  /** Префикс источника в arbiDexMarketData (например, 'binance', 'dex:arbitrum') */
  sourcePrefix: string;
  /** Символ пары в arbiDexMarketData (например, 'ETHUSDC', '0x82af...0xaf88...') */
  symbol: string;
}

/** Контракты токенов на Arbitrum */
const ARBITRUM_WETH = '0x82af49447d8a07e3bd95bd0d56f35241523fbab1';
const ARBITRUM_USDC = '0xaf88d065e77c8cc2239327c5edb3a432268e5831';

/**
 * Таблица маппинга: `sourceId::pairId` → PriceKeyMapping
 */
const MAPPING: Record<string, PriceKeyMapping> = {
  // ── Binance ──
  'cex_binance::USDC_WETH':  { sourcePrefix: 'binance', symbol: 'ETHUSDC' },
  'cex_binance::ETH_USDT':   { sourcePrefix: 'binance', symbol: 'ETHUSDT' },

  // ── MEXC ──
  'cex_mex::ETH_USDT':       { sourcePrefix: 'mexc', symbol: 'ETHUSDT' },
  'cex_mex::USDC_WETH':      { sourcePrefix: 'mexc', symbol: 'ETHUSDC' },

  // ── Bybit ──
  'cex_bybit::ETH_USDT':     { sourcePrefix: 'bybit', symbol: 'ETHUSDT' },
  'cex_bybit::USDC_WETH':    { sourcePrefix: 'bybit', symbol: 'ETHUSDC' },

  // ── OKX ──
  'cex_okx::ETH_USDT':       { sourcePrefix: 'okx', symbol: 'ETHUSDT' },
  'cex_okx::USDC_WETH':      { sourcePrefix: 'okx', symbol: 'ETHUSDC' },

  // ── KuCoin ──
  'cex_kucoin::ETH_USDT':    { sourcePrefix: 'kucoin', symbol: 'ETHUSDT' },
  'cex_kucoin::USDC_WETH':   { sourcePrefix: 'kucoin', symbol: 'ETHUSDC' },

  // ── Gate.io ──
  'cex_gateio::ETH_USDT':    { sourcePrefix: 'gateio', symbol: 'ETHUSDT' },
  'cex_gateio::USDC_WETH':   { sourcePrefix: 'gateio', symbol: 'ETHUSDC' },

  // ── DEX Arbitrum ──
  'dex_arbitrum::USDC_WETH':  { sourcePrefix: 'dex:arbitrum', symbol: `${ARBITRUM_WETH}${ARBITRUM_USDC}` },
};

/**
 * Получить ключи arbiDexMarketData (bid + ask) для пары sourceId + pairId.
 * Возвращает null если маппинг не найден.
 */
export function getPriceStoreKeys(
  sourceId: string,
  pairId: string,
): { bidKey: string; askKey: string; mapping: PriceKeyMapping } | null {
  const m = MAPPING[`${sourceId}::${pairId}`];
  if (!m) return null;
  return {
    bidKey: `${m.sourcePrefix}${m.symbol}bidPrice`,
    askKey: `${m.sourcePrefix}${m.symbol}askPrice`,
    mapping: m,
  };
}

/**
 * Обратный маппинг: ключ arbiDexMarketData (без суффикса bidPrice/askPrice) → { sourceId, pairId }
 * Используется для построения таблицы Latest Quotes из snapshot.
 */
const REVERSE_MAPPING: Record<string, { sourceId: string; pairId: string }> = {};
for (const [compositeKey, mapping] of Object.entries(MAPPING)) {
  const [sourceId, pairId] = compositeKey.split('::');
  const storePrefix = `${mapping.sourcePrefix}${mapping.symbol}`;
  REVERSE_MAPPING[storePrefix] = { sourceId, pairId };
}

/** Известные префиксы источников, отсортированные по длине (longest first) */
const KNOWN_SOURCES = [
  'dex:arbitrum', 'binance', 'kucoin', 'gateio', 'bybit', 'mexc', 'okx',
];

/**
 * Разбирает ключ arbiDexMarketData на составляющие.
 * Например: `mexcETHUSDTbidPrice` → { source: 'mexc', symbol: 'ETHUSDT', field: 'bidPrice', sourceId: 'cex_mex', pairId: 'ETH_USDT' }
 * Возвращает null если ключ не удалось разобрать.
 */
export function parseStoreKey(key: string): {
  source: string;
  symbol: string;
  field: 'bidPrice' | 'askPrice';
  sourceId: string | null;
  pairId: string | null;
} | null {
  let field: 'bidPrice' | 'askPrice';
  let rest: string;

  if (key.endsWith('bidPrice')) {
    field = 'bidPrice';
    rest = key.slice(0, -8);
  } else if (key.endsWith('askPrice')) {
    field = 'askPrice';
    rest = key.slice(0, -8);
  } else {
    return null;
  }

  // Ищем известный источник (longest match first)
  for (const src of KNOWN_SOURCES) {
    if (rest.startsWith(src)) {
      const symbol = rest.slice(src.length);
      const reverse = REVERSE_MAPPING[`${src}${symbol}`];
      return {
        source: src,
        symbol,
        field,
        sourceId: reverse?.sourceId ?? null,
        pairId: reverse?.pairId ?? null,
      };
    }
  }

  return null;
}

import { Injectable, NotFoundException, BadRequestException, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { ConfigService } from '@nestjs/config';
import { HttpService } from '@nestjs/axios';
import { firstValueFrom } from 'rxjs';
import { Subscription } from '../subscriptions/entities/subscription.entity';
import { getPriceStoreKeys } from './price-key-mapping';

/** Точка из PriceStore arbiDexServerBots */
interface BotsPricePoint {
  t: number; // timestamp ms
  v: number; // value
}

/** Ответ от /prices/keys (POST) — каждый ключ содержит объект с полем points */
interface BotsPriceKeyData {
  points: BotsPricePoint[];
  count?: number;
  last?: BotsPricePoint;
}

interface BotsPriceKeysResponse {
  [key: string]: BotsPriceKeyData;
}

/** Конфиг серии для фронтенда */
export interface PriceSeriesConfig {
  key: string;
  name: string;
  color: string;
}

/** Точка данных для фронтенда */
export interface ChartPricePoint {
  time: number;
  [field: string]: number;
}

/** Полный ответ для фронтенда */
export interface SubscriptionPriceData {
  series: PriceSeriesConfig[];
  data: ChartPricePoint[];
}

@Injectable()
export class PricesService {
  private readonly logger = new Logger(PricesService.name);
  private readonly marketDataUrl: string;

  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
    @InjectRepository(Subscription)
    private readonly subsRepo: Repository<Subscription>,
  ) {
    this.marketDataUrl = this.configService.get<string>('marketData.url') ?? 'http://45.135.182.251:3002';
  }

  /**
   * Получить ценовые данные по subscriptionId.
   * Маппит sourceId+pairId → ключи PriceStore, запрашивает историю из arbiDexServerBots,
   * трансформирует в формат PriceChartComponent.
   */
  async getPricesBySubscription(subscriptionId: string, userId: string): Promise<SubscriptionPriceData> {
    // 1. Найти подписку
    const sub = await this.subsRepo.findOne({ where: { id: subscriptionId, userId } });
    if (!sub) {
      throw new NotFoundException('Подписка не найдена');
    }

    // 2. Маппинг в ключи PriceStore
    const keys = getPriceStoreKeys(sub.sourceId, sub.pairId);
    if (!keys) {
      throw new BadRequestException(
        `Маппинг не найден для sourceId="${sub.sourceId}", pairId="${sub.pairId}". ` +
        `Проверьте конфигурацию price-key-mapping.ts`,
      );
    }

    // 3. Запрос к arbiDexServerBots
    const { bidKey, askKey, mapping } = keys;
    let botsData: BotsPriceKeysResponse;

    try {
      const response = await firstValueFrom(
        this.httpService.post<BotsPriceKeysResponse>(`${this.marketDataUrl}/store/keys`, {
          keys: [bidKey, askKey],
        }),
      );
      botsData = response.data;
    } catch (error) {
      this.logger.error(`Ошибка при запросе к arbiDexMarketData: ${error.message}`);
      throw new BadRequestException(
        `Не удалось получить данные от сервиса котировок (${this.marketDataUrl}). ` +
        `Убедитесь что arbiDexMarketData запущен.`,
      );
    }

    // 4. Трансформация в формат PriceChartComponent
    const bidPoints: BotsPricePoint[] = botsData[bidKey]?.points ?? [];
    const askPoints: BotsPricePoint[] = botsData[askKey]?.points ?? [];

    // Merge bid и ask по timestamp с помощью Map
    const timeMap = new Map<number, ChartPricePoint>();

    for (const p of bidPoints) {
      timeMap.set(p.t, { time: p.t, bidPrice: p.v, askPrice: 0 });
    }

    for (const p of askPoints) {
      const existing = timeMap.get(p.t);
      if (existing) {
        existing.askPrice = p.v;
      } else {
        timeMap.set(p.t, { time: p.t, bidPrice: 0, askPrice: p.v });
      }
    }

    // Сортировка по времени, заполнение пропусков предыдущим значением
    const sorted = Array.from(timeMap.values()).sort((a, b) => a.time - b.time);

    let lastBid = 0;
    let lastAsk = 0;
    for (const point of sorted) {
      if (point.bidPrice === 0 && lastBid !== 0) point.bidPrice = lastBid;
      if (point.askPrice === 0 && lastAsk !== 0) point.askPrice = lastAsk;
      lastBid = point.bidPrice;
      lastAsk = point.askPrice;
    }

    // 5. Конфиг серий
    const sourceName = mapping.sourcePrefix;
    const series: PriceSeriesConfig[] = [
      { key: 'bidPrice', name: `${sourceName} Bid`, color: '#0ecb81' },
      { key: 'askPrice', name: `${sourceName} Ask`, color: '#f6465d' },
    ];

    return { series, data: sorted };
  }
}

import { Injectable, NotFoundException, BadRequestException, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { ConfigService } from '@nestjs/config';
import { HttpService } from '@nestjs/axios';
import { firstValueFrom } from 'rxjs';
import { Subscription } from '../subscriptions/entities/subscription.entity';
import { buildStoreKeys, detectKeyFormat, SOURCE_META } from './market-data-keys';

/** Точка из PriceStore arbiDexServerBots */
interface BotsPricePoint {
  t: number; // timestamp ms
  v: number; // value
}

/** Ответ от /prices/keys (POST) — каждый ключ содержит объект с полем points */
interface BotsPriceKeyData {
  points: BotsPricePoint[];
  count?: number;
  last?: BotsPricePoint;
}

interface BotsPriceKeysResponse {
  [key: string]: BotsPriceKeyData;
}

/** Конфиг серии для фронтенда */
export interface PriceSeriesConfig {
  key: string;
  name: string;
  color: string;
}

/** Точка данных для фронтенда */
export interface ChartPricePoint {
  time: number;
  [field: string]: number;
}

/** Полный ответ для фронтенда */
export interface SubscriptionPriceData {
  series: PriceSeriesConfig[];
  data: ChartPricePoint[];
}

@Injectable()
export class PricesService {
  private readonly logger = new Logger(PricesService.name);
  private readonly marketDataUrl: string;

  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
    @InjectRepository(Subscription)
    private readonly subsRepo: Repository<Subscription>,
  ) {
    this.marketDataUrl = this.configService.get<string>('marketData.url') ?? 'http://45.135.182.251:3002';
  }

  /**
   * Получить ценовые данные по subscriptionId.
   * Маппит sourceId+pairId → ключи PriceStore, запрашивает историю из arbiDexServerBots,
   * трансформирует в формат PriceChartComponent.
   */
  async getPricesBySubscription(subscriptionId: string, userId: string): Promise<SubscriptionPriceData> {
    // 1. Найти подписку
    const sub = await this.subsRepo.findOne({ where: { id: subscriptionId, userId } });
    if (!sub) {
      throw new NotFoundException('Подписка не найдена');
    }

    // 2. Определяем формат ключей и строим bid/ask ключи
    let format: 'pipe' | 'concat' = 'concat';
    try {
      const keysResp = await firstValueFrom(
        this.httpService.get<string[]>(`${this.marketDataUrl}/store/keys`),
      );
      format = detectKeyFormat(keysResp.data);
    } catch {
      // используем формат по умолчанию
    }

    const keys = buildStoreKeys(sub.sourceId, sub.pairId, format);
    if (!keys) {
      throw new BadRequestException(
        `Не удалось построить ключи для sourceId="${sub.sourceId}", pairId="${sub.pairId}".`,
      );
    }

    // 3. Запрос к arbiDexMarketData
    const { bidKey, askKey } = keys;
    let botsData: BotsPriceKeysResponse;

    try {
      const response = await firstValueFrom(
        this.httpService.post<BotsPriceKeysResponse>(`${this.marketDataUrl}/store/keys`, {
          keys: [bidKey, askKey],
        }),
      );
      botsData = response.data;
    } catch (error) {
      this.logger.error(`Ошибка при запросе к arbiDexMarketData: ${error.message}`);
      throw new BadRequestException(
        `Не удалось получить данные от сервиса котировок (${this.marketDataUrl}). ` +
        `Убедитесь что arbiDexMarketData запущен.`,
      );
    }

    // 4. Трансформация в формат PriceChartComponent
    const bidPoints: BotsPricePoint[] = botsData[bidKey]?.points ?? [];
    const askPoints: BotsPricePoint[] = botsData[askKey]?.points ?? [];

    // Merge bid и ask по timestamp с помощью Map
    const timeMap = new Map<number, ChartPricePoint>();

    for (const p of bidPoints) {
      timeMap.set(p.t, { time: p.t, bidPrice: p.v, askPrice: 0 });
    }

    for (const p of askPoints) {
      const existing = timeMap.get(p.t);
      if (existing) {
        existing.askPrice = p.v;
      } else {
        timeMap.set(p.t, { time: p.t, bidPrice: 0, askPrice: p.v });
      }
    }

    // Сортировка по времени, заполнение пропусков предыдущим значением
    const sorted = Array.from(timeMap.values()).sort((a, b) => a.time - b.time);

    let lastBid = 0;
    let lastAsk = 0;
    for (const point of sorted) {
      if (point.bidPrice === 0 && lastBid !== 0) point.bidPrice = lastBid;
      if (point.askPrice === 0 && lastAsk !== 0) point.askPrice = lastAsk;
      lastBid = point.bidPrice;
      lastAsk = point.askPrice;
    }

    // 5. Конфиг серий
    const sourceName = SOURCE_META[sub.sourceId]?.displayName ?? sub.sourceId;
    const series: PriceSeriesConfig[] = [
      { key: 'bidPrice', name: `${sourceName} Bid`, color: '#0ecb81' },
      { key: 'askPrice', name: `${sourceName} Ask`, color: '#f6465d' },
    ];

    return { series, data: sorted };
  }
}

import { Controller, Get, UseGuards } from '@nestjs/common';
import { ApiBearerAuth, ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { QuotesService, QuoteDto } from './quotes.service';

@ApiTags('Quotes')
@ApiBearerAuth()
@UseGuards(JwtAuthGuard)
@Controller('quotes')
export class QuotesController {
  constructor(private readonly quotesService: QuotesService) {}

  @Get('latest')
  @ApiOperation({
    summary: 'Последние котировки',
    description:
      'Возвращает последние bid/ask котировки для всех доступных пар из arbiDexMarketData. ' +
      'Данные берутся из snapshot — по одной точке на каждый ключ.',
  })
  @ApiResponse({ status: 200, description: 'Массив котировок' })
  async getLatestQuotes(): Promise<QuoteDto[]> {
    return this.quotesService.getLatestQuotes();
  }
}

import { Module } from '@nestjs/common';
import { HttpModule } from '@nestjs/axios';
import { QuotesController } from './quotes.controller';
import { QuotesService } from './quotes.service';

@Module({
  imports: [HttpModule.register({ timeout: 10000 })],
  controllers: [QuotesController],
  providers: [QuotesService],
})
export class QuotesModule {}

import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { HttpService } from '@nestjs/axios';
import { firstValueFrom } from 'rxjs';
import {
  parseMarketDataKey,
  makePairId,
  SOURCE_META,
} from '../prices/market-data-keys';

/** Точка из arbiDexMarketData snapshot */
interface DataPoint {
  t: number;
  v: number;
}

/** Формат snapshot: ключ → последняя точка */
interface SnapshotResponse {
  [key: string]: DataPoint | null;
}

/** Котировка для фронтенда */
export interface QuoteDto {
  sourceId: string;
  pairId: string;
  bid: number;
  ask: number;
  mid: number;
  spread: number;
  spreadPct: number;
  timestamp: number;
}

@Injectable()
export class QuotesService {
  private readonly logger = new Logger(QuotesService.name);
  private readonly marketDataUrl: string;

  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
  ) {
    this.marketDataUrl =
      this.configService.get<string>('marketData.url') ?? 'http://45.135.182.251:3002';
  }

  /**
   * Получить последние котировки из arbiDexMarketData.
   * Запрашивает /store/snapshot, группирует bid/ask по source+pair,
   * маппит обратно на sourceId/pairId.
   */
  async getLatestQuotes(): Promise<QuoteDto[]> {
    let snapshot: SnapshotResponse;

    try {
      const response = await firstValueFrom(
        this.httpService.get<SnapshotResponse>(`${this.marketDataUrl}/store/snapshot`),
      );
      snapshot = response.data;
    } catch (error) {
      this.logger.error(`Ошибка при запросе snapshot из arbiDexMarketData: ${error.message}`);
      return [];
    }

    // Группируем bid/ask по ключу source+pair
    const groups = new Map<string, {
      sourceId: string;
      pairId: string;
      bid?: DataPoint;
      ask?: DataPoint;
    }>();

    for (const [key, point] of Object.entries(snapshot)) {
      if (!point) continue;

      const parsed = parseMarketDataKey(key);
      if (!parsed) {
        this.logger.debug(`Пропущен ключ без маппинга: ${key}`);
        continue;
      }

      const sourceId = parsed.source;
      const pairId = makePairId(parsed.base, parsed.quote);
      const groupKey = `${sourceId}::${pairId}`;

      if (!groups.has(groupKey)) {
        groups.set(groupKey, { sourceId, pairId });
      }

      const group = groups.get(groupKey)!;
      if (parsed.field === 'bidPrice') {
        group.bid = point;
      } else {
        group.ask = point;
      }
    }

    // Формируем массив котировок
    const quotes: QuoteDto[] = [];

    for (const group of groups.values()) {
      const bid = group.bid?.v ?? 0;
      const ask = group.ask?.v ?? 0;

      if (bid === 0 && ask === 0) continue;

      const mid = (bid + ask) / 2;
      const spread = ask - bid;
      const spreadPct = mid > 0 ? spread / mid : 0;
      const timestamp = Math.max(group.bid?.t ?? 0, group.ask?.t ?? 0);

      quotes.push({
        sourceId: group.sourceId,
        pairId: group.pairId,
        bid: +bid.toFixed(6),
        ask: +ask.toFixed(6),
        mid: +mid.toFixed(6),
        spread: +spread.toFixed(6),
        spreadPct: +spreadPct.toFixed(8),
        timestamp,
      });
    }

    // Сортируем: сначала по sourceId, потом по pairId
    quotes.sort((a, b) =>
      a.sourceId.localeCompare(b.sourceId) || a.pairId.localeCompare(b.pairId),
    );

    return quotes;
  }
}

import { ApplicationConfig, provideZoneChangeDetection } from '@angular/core';
